// src/components/EditableEvent.js

import React, { useState, useEffect } from 'react';

const EditableEvent = ({ event }) => {
  const [editableEvent, setEditableEvent] = useState(event);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setEditableEvent((prevEvent) => ({ ...prevEvent, [name]: value }));
  };

  const handleUpdate = async () => {
    try {
      const response = await fetch('http://localhost:8000/event/edit', {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(editableEvent),
      });

      if (response.ok) {
        console.log('Event updated successfully!');
        // ここで成功時の処理を追加する（例: リストを再取得するなど）
      } else {
        console.error('Failed to update event');
      }
    } catch (error) {
      console.error('Error:', error);
    }
  };

  return (
    <div>
      <h2>Edit Event</h2>
      <label>
        Event ID:
        <input
          type="number"
          name="event_id"
          value={editableEvent.event_id}
          onChange={handleChange}
          readOnly
        />
      </label>
      <br />
      <label>
        Event Name:
        <input
          type="text"
          name="event_name"
          value={editableEvent.event_name}
          onChange={handleChange}
        />
      </label>
      <br />
      <label>
        Event State:
        <input
          type="text"
          name="event_state"
          value={editableEvent.event_state}
          onChange={handleChange}
        />
      </label>
      <br />
      <button onClick={handleUpdate}>Update Event</button>
    </div>
  );
};

const EventList = () => {
  const [events, setEvents] = useState([]);
  const [selectedEvent, setSelectedEvent] = useState(null);

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const response = await fetch('http://localhost:8000/event/get');
        const data = await response.json();
        setEvents(data);
      } catch (error) {
        console.error('Error fetching events:', error);
      }
    };

    fetchEvents();
  }, []);

  const handleEventClick = (event) => {
    setSelectedEvent(event);
  };

  return (
    <div>
      <h2>Event List</h2>
      <ul>
        {events.map((event) => (
          <li key={event.event_id} onClick={() => handleEventClick(event)}>
            {event.event_name}
          </li>
        ))}
      </ul>
      {selectedEvent && <EditableEvent event={selectedEvent} />}
    </div>
  );
};

export default EventList;
